    if (_mayBeLeaf) {
        _mayBeLeaf = false;
        // 06-Jan-2015, tatu: as per [dataformat-xml#180], need to
        //    expose as empty Object, not null
        // However, in array context, we must return an empty object instead of null
        if (_parsingContext.inArray()) {
            // Return START_OBJECT followed by END_OBJECT to create an empty object
            // Set the next token to be the END_OBJECT
            _nextToken = JsonToken.END_OBJECT;
            _parsingContext = _parsingContext.createChildObjectContext(-1, -1);
